/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto nodeA = std::make_shared<TestTransactionalObserver>("NodeA");
    auto nodeB = std::make_shared<TestTransactionalObserver>("NodeB");

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship (A observes B)
    graph.addObserver(nodeB, nodeA);

    // 4. Notify target and verify relationship works
    nodeB->valueChanged(true);

    // Verify A was notified
    if (nodeA->getCallCount() != 1 || !nodeA->wasChanged()) {
        return false; // Initial relationship not working
    }

    // 5. Reset observer for next test
    nodeA->reset();
    nodeB->reset();

    // 6. Attempt transactional update that would create cycle
    bool cycleDetected = false;
    try {
        // Try to create a cycle: B observes A (but A already observes B)
        // This should be rejected by the transactional update
        graph.updateObserversTransactional(nodeA, nodeB);
    } catch (const std::exception& e) {
        // 7. Catch cycle exception if thrown
        cycleDetected = true;
    }

    // 8. Notify target again
    nodeB->valueChanged(true);

    // 9. Verify original relationship is preserved
    if (nodeA->getCallCount() != 1 || !nodeA->wasChanged()) {
        return false; // Original relationship broken
    }

    // 10. Return success status
    // Test passes if cycle was detected and original relationship preserved
    return cycleDetected;
}

}  // namespace test_reaction
