#pragma once

#include <reaction/reaction.h>
#include <tuple>
#include <string>

namespace test_reaction {

// ============================================
// Function implementations
// ============================================

/**
 * Function: Test filter trigger with conditional recomputation
 *
 * @param initialValue Initial sensor value
 * @param firstUpdate First update (expected to be within threshold)
 * @param secondUpdate Second update (expected to exceed threshold)
 * @param diffThreshold Minimum delta to trigger recomputation
 * @param levelThreshold Threshold to categorize HIGH vs NORMAL
 * @return std::tuple<std::string, int, int>
 *         {final status string, recompute count after first update, recompute count after second update}
 */
std::tuple<std::string, int, int> test_filter_trigger(double initialValue,
                                                      double firstUpdate,
                                                      double secondUpdate,
                                                      double diffThreshold,
                                                      double levelThreshold) {
    // 1. Create reactive variable (sensor)
    auto sensor = reaction::var(initialValue);

    // 2. Create variables to track recomputation count and last processed value
    int recomputeCount = 0;
    double lastProcessed = initialValue;

    // 3. Create filter-triggered calculation
    auto status = reaction::filter(
        [&]() -> bool {
            // Only recompute if the change exceeds the threshold
            return std::abs(sensor.get() - lastProcessed) >= diffThreshold;
        },
        [&]() -> std::string {
            recomputeCount++;
            double current = sensor.get();
            lastProcessed = current;

            // Categorize based on level threshold
            if (current > levelThreshold) {
                return "HIGH";
            } else {
                return "NORMAL";
            }
        }
    );

    // Initialize status
    std::string currentStatus = status.get();

    // 5. Update sensor with first value
    sensor.set(firstUpdate);

    // 6. Record recompute count after first update
    int countAfterFirst = recomputeCount;
    currentStatus = status.get();

    // 7. Update sensor with second value
    sensor.set(secondUpdate);

    // 8. Record recompute count after second update
    int countAfterSecond = recomputeCount;

    // 9. Get final status
    std::string finalStatus = status.get();

    // 10. Return final status and counts
    return {finalStatus, countAfterFirst, countAfterSecond};
}

}  // namespace test_reaction
```

This implementation uses the `reaction` library to:

1. Create a reactive variable `sensor` with the initial value
2. Track recomputation count and last processed value
3. Create a filter-triggered calculation using `reaction::filter()` that only recomputes when the change exceeds `diffThreshold`
4. The filter condition checks if the absolute difference between current sensor value and last processed value meets/exceeds the threshold
5. When triggered, the computation increments the counter, updates the last processed value, and categorizes the status as "HIGH" or "NORMAL" based on `levelThreshold`
6. Updates the sensor and records recomputation counts after each update
7. Returns the final status and both recomputation counts

The filter ensures that the expensive categorization logic only runs when the sensor value changes significantly enough to warrant recomputation.

