    reaction::Resource<int> resource(initialValue);

    // Variable to track whether operation reported a change
    bool operationReportedChange = false;

    // Perform an atomic operation that adds delta to the value
    // The atomic method typically returns a boolean indicating if a change occurred
    operationReportedChange = resource.atomic([delta](int& value) {
        value += delta;
        // Return true to indicate the value was modified
        return true;
    });

    // Get the final value
    int finalValue = resource.get();

    // Return resource atomic result
    return ResourceAtomicResult{finalValue, operationReportedChange};
}

