    varB = b + 10;
    boolVar = false; // Flip boolean value
    intVar = 7; // Update integer value

    // 9. Get updated values
    int updatedNegatedSum = negatedSum.get();
    bool logicalNotAfterFlip = logicalNot.get();
    int bitwiseNotValue = bitwiseNot.get();

    // 10. Return unary expression snapshot
    return UnaryExpressionSnapshot{
